1	//! SVG diagram rendering for MLPL arrays.
2	
3	mod bar;
4	mod heatmap;
5	mod helpers;
6	mod line;
7	mod scatter;
8	
9	use std::fmt;
10	
11	use mlpl_array::DenseArray;
12	
13	pub use bar::render_bar;
14	pub use heatmap::render_heatmap;
15	pub use line::render_line;
16	pub use scatter::render_scatter;
17	
18	pub(crate) use helpers::{H, PAD, W, bounds, scale, write_svg_close, write_svg_open};
19	
20	/// Errors produced by SVG rendering.
21	#[derive(Clone, Debug, PartialEq)]
22	pub enum VizError {
23	    /// The data shape is not valid for the requested diagram.
24	    InvalidShape(String),
25	    /// The diagram type name is not recognized.
26	    UnknownType(String),
27	}
28	
29	impl fmt::Display for VizError {
30	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
31	        match self {
32	            Self::InvalidShape(s) => write!(f, "invalid shape for diagram: {s}"),
33	            Self::UnknownType(s) => write!(f, "unknown svg type: '{s}'"),
34	        }
35	    }
36	}
37	
38	impl std::error::Error for VizError {}
39	
40	/// Dispatch on a diagram type name. Returns the rendered SVG string.
41	pub fn render(data: &DenseArray, type_name: &str) -> Result<String, VizError> {
42	    match type_name {
