//! SVG diagram rendering for MLPL arrays.

mod bar;
mod decision_boundary;
mod heatmap;
mod helpers;
mod line;
mod scatter;

use std::fmt;

use mlpl_array::DenseArray;

pub use bar::render_bar;
pub use decision_boundary::render_decision_boundary;
pub use heatmap::render_heatmap;
pub use line::render_line;
pub use scatter::render_scatter;

pub(crate) use helpers::{H, PAD, W, bounds, scale, write_svg_close, write_svg_open};

/// Errors produced by SVG rendering.
#[derive(Clone, Debug, PartialEq)]
pub enum VizError {
    /// The data shape is not valid for the requested diagram.
    InvalidShape(String),
    /// The diagram type name is not recognized.
    UnknownType(String),
}

impl fmt::Display for VizError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::InvalidShape(s) => write!(f, "invalid shape for diagram: {s}"),
            Self::UnknownType(s) => write!(f, "unknown svg type: '{s}'"),
        }
    }
}

impl std::error::Error for VizError {}

/// Dispatch on a diagram type name. Returns the rendered SVG string.
pub fn render(data: &DenseArray, type_name: &str) -> Result<String, VizError> {
    render_with_aux(data, type_name, None)
}

/// Dispatch on a diagram type name with an optional auxiliary array.
/// Diagrams that need extra inputs (e.g. `decision_boundary` needs the
/// training points) read them from `aux`.
pub fn render_with_aux(
    data: &DenseArray,
    type_name: &str,
    aux: Option<&DenseArray>,
) -> Result<String, VizError> {
    match type_name {
        "scatter" => render_scatter(data),
        "line" => render_line(data),
        "bar" => render_bar(data),
        "heatmap" => render_heatmap(data),
        "decision_boundary" => {
            let training = aux.ok_or_else(|| {
                VizError::InvalidShape(
                    "decision_boundary requires a third argument (training points Nx3)".into(),
                )
            })?;
            render_decision_boundary(data, training)
        }
        other => Err(VizError::UnknownType(other.to_string())),
    }
}

//! Built-in function implementations.

use mlpl_array::{DenseArray, Shape};

use crate::error::RuntimeError;
use crate::math_builtins;

macro_rules! check_arity {
    ($name:expr, $expected:expr, $args:expr) => {
        if $args.len() != $expected {
            return Err(RuntimeError::ArityMismatch {
                func: $name.into(),
                expected: $expected,
                got: $args.len(),
            });
        }
    };
}

/// Dispatch a built-in function call by name.
pub fn call_builtin(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    // Try math/constructor builtins first
    if let Some(result) = math_builtins::try_call(name, args.clone()) {
        return result;
    }
    match name {
        "iota" => builtin_iota(name, args),
        "shape" => builtin_shape(name, args),
        "rank" => builtin_rank(name, args),
        "reshape" => builtin_reshape(name, args),
        "transpose" => builtin_transpose(name, args),
        "reduce_add" | "reduce_mul" => builtin_reduce(name, args),
        "dot" => {
            check_arity!(name, 2, args);
            Ok(args[0].dot(&args[1])?)
        }
        "matmul" => {
            check_arity!(name, 2, args);
            Ok(args[0].matmul(&args[1])?)
        }
        "grid" => builtin_grid(name, args),
        _ => Err(RuntimeError::UnknownFunction(name.into())),
    }
}

fn builtin_grid(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 2, args);
    let bounds = args[0].data();
    if args[0].rank() != 1 || bounds.len() != 4 {
        return Err(RuntimeError::InvalidArgument {
            func: name.into(),
            reason: "bounds must be a length-4 vector [xmin, xmax, ymin, ymax]".into(),
        });
    }
    if args[1].rank() != 0 {
        return Err(RuntimeError::InvalidArgument {
            func: name.into(),
            reason: "n must be a scalar".into(),
        });
    }
    let n = args[1].data()[0] as usize;
    if n == 0 {
        return Err(RuntimeError::InvalidArgument {
            func: name.into(),
            reason: "n must be > 0".into(),
        });
    }
    let (xmin, xmax, ymin, ymax) = (bounds[0], bounds[1], bounds[2], bounds[3]);
    let denom = if n == 1 { 1.0 } else { (n - 1) as f64 };
    let mut data = Vec::with_capacity(n * n * 2);
    for i in 0..n {
        let y = ymin + (ymax - ymin) * (i as f64) / denom;
        for j in 0..n {
            let x = xmin + (xmax - xmin) * (j as f64) / denom;
            data.push(x);
            data.push(y);
        }
    }
    Ok(DenseArray::new(Shape::new(vec![n * n, 2]), data)?)
}

fn builtin_iota(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    if args[0].rank() != 0 {
        return Err(RuntimeError::InvalidArgument {
            func: name.into(),
            reason: format!("expected scalar, got rank {}", args[0].rank()),
        });
    }
    let n = args[0].data()[0] as usize;
    let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
    Ok(DenseArray::from_vec(data))
}

fn builtin_shape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    let dims: Vec<f64> = args[0].shape().dims().iter().map(|&d| d as f64).collect();
    Ok(DenseArray::from_vec(dims))
}

fn builtin_rank(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    Ok(DenseArray::from_scalar(args[0].rank() as f64))
}

fn builtin_reshape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 2, args);
    let shape_data = args[1].data();
    let dims: Vec<usize> = shape_data.iter().map(|&d| d as usize).collect();
    Ok(args[0].reshape(Shape::new(dims))?)
}

fn builtin_transpose(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    Ok(args[0].transpose())
}

fn builtin_reduce(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    if args.len() != 1 && args.len() != 2 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 1,
            got: args.len(),
        });
    }
    let (identity, op): (f64, fn(f64, f64) -> f64) = match name {
        "reduce_add" => (0.0, |a, b| a + b),
        "reduce_mul" => (1.0, |a, b| a * b),
        _ => unreachable!(),
    };
    if args.len() == 2 {
        if args[1].rank() != 0 {
            return Err(RuntimeError::InvalidArgument {
                func: name.into(),
                reason: format!("axis must be scalar, got rank {}", args[1].rank()),
            });
        }
        let axis = args[1].data()[0] as usize;
        Ok(args[0].reduce_axis(axis, identity, op)?)
    } else {
        let result = args[0].data().iter().copied().fold(identity, op);
        Ok(DenseArray::from_scalar(result))
    }
}

