        let cx = scale(i as f64, xmin, xmax, 0);
        let cy = scale(v, ymin, ymax, 1);
        if !pts.is_empty() {
            pts.push(' ');
        }
        pts.push_str(&format!("{cx:.1},{cy:.1}"));
    }
    out.push_str(&format!(
        "<polyline points=\"{pts}\" fill=\"none\" stroke=\"#a6e3a1\" stroke-width=\"2\"/>"
    ));
    out.push_str(&format!(
        "<text x=\"{:.1}\" y=\"18\" fill=\"#cdd6f4\" font-family=\"monospace\" font-size=\"12\">loss</text>",
        PAD
    ));
    out.push_str(&format!(
        "<text x=\"{:.1}\" y=\"{:.1}\" fill=\"#a6adc8\" font-family=\"monospace\" font-size=\"10\">{ymax:.3}</text>",
        4.0, PAD + 4.0,
    ));
    out.push_str(&format!(
        "<text x=\"{:.1}\" y=\"{:.1}\" fill=\"#a6adc8\" font-family=\"monospace\" font-size=\"10\">{ymin:.3}</text>",
        4.0, H - PAD,
    ));
    write_svg_close(&mut out);
    Ok(out)
}

/// Confusion matrix from two equal-length vectors of class ids.
/// Renders a KxK heatmap with the cell counts overlaid as text.
pub fn analysis_confusion_matrix(
    predicted: &DenseArray,
    actual: &DenseArray,
) -> Result<String, VizError> {
    if predicted.rank() != 1 || actual.rank() != 1 {
        return Err(VizError::InvalidShape(
            "confusion_matrix expects two vectors".into(),
        ));
    }
    let p = predicted.data();
    let a = actual.data();
    if p.len() != a.len() {
        return Err(VizError::InvalidShape(format!(
            "confusion_matrix length mismatch: {} vs {}",
            p.len(),
            a.len()
        )));
    }
    let mut out = String::new();
    write_svg_open(&mut out);
    if p.is_empty() {
        write_svg_close(&mut out);
        return Ok(out);
    }
    let mut k = 0_usize;
    for &v in p.iter().chain(a.iter()) {
        let c = v as usize + 1;
        if c > k {
            k = c;
        }
    }
    let mut counts = vec![0_usize; k * k];
    for i in 0..p.len() {
        let pi = p[i] as usize;
        let ai = a[i] as usize;
        counts[ai * k + pi] += 1;
    }
    let max = counts.iter().copied().max().unwrap_or(1).max(1) as f64;
    let plot_w = W - 2.0 * PAD;
    let plot_h = H - 2.0 * PAD;
    let cw = plot_w / k as f64;
    let ch = plot_h / k as f64;
    for r in 0..k {
        for c in 0..k {
            let v = counts[r * k + c] as f64;
            let t = (v / max).clamp(0.0, 1.0);
            let shade = (40.0 + t * 200.0) as u8;
            let x = PAD + cw * c as f64;
            let y = PAD + ch * r as f64;
            out.push_str(&format!(
                "<rect x=\"{x:.1}\" y=\"{y:.1}\" width=\"{cw:.1}\" height=\"{ch:.1}\" fill=\"rgb({shade},{shade},255)\"/>"
            ));
            out.push_str(&format!(
                "<text x=\"{:.1}\" y=\"{:.1}\" fill=\"#1e1e2e\" font-family=\"monospace\" font-size=\"12\" text-anchor=\"middle\">{}</text>",
                x + cw / 2.0,
                y + ch / 2.0 + 4.0,
                counts[r * k + c]
            ));
        }
    }
    write_svg_close(&mut out);
    Ok(out)
}

/// Render a 2D classifier surface with separately-supplied training
/// points and labels. `grid_outputs` is a length-(rows*cols) vector,
/// `dims` is a length-2 vector `[rows, cols]`, `points` is an Nx2
/// matrix in any data range, and `labels` is a length-N vector.
/// The training points are normalized into the plot region by their
/// bounding box.
pub fn analysis_boundary_2d(
    grid_outputs: &DenseArray,
    dims: &DenseArray,
    points: &DenseArray,
    labels: &DenseArray,
) -> Result<String, VizError> {
    if dims.rank() != 1 || dims.data().len() != 2 {
        return Err(VizError::InvalidShape(
            "boundary_2d dims must be [rows, cols]".into(),
        ));
    }
    let rows = dims.data()[0] as usize;
    let cols = dims.data()[1] as usize;
    let raw = grid_outputs.data();
    if raw.len() != rows * cols {
        return Err(VizError::InvalidShape(format!(
            "boundary_2d grid_outputs has {} values but dims expect {}",
            raw.len(),
            rows * cols
        )));
    }
    let pdims = points.shape().dims();
    if pdims.len() != 2 || pdims[1] != 2 {
        return Err(VizError::InvalidShape(format!(
            "boundary_2d points must be Nx2, got {pdims:?}"
        )));
    }
    let n = pdims[0];
    if labels.rank() != 1 || labels.data().len() != n {
        return Err(VizError::InvalidShape(
            "boundary_2d labels length must match points".into(),
        ));
    }
    let mut out = String::new();
    write_svg_open(&mut out);
    let (lo, hi) = data_range(raw);
    let span = if (hi - lo).abs() < f64::EPSILON { 1.0 } else { hi - lo };
    let plot_w = W - 2.0 * PAD;
    let plot_h = H - 2.0 * PAD;
    let cw = plot_w / cols as f64;
    let ch = plot_h / rows as f64;
    for r in 0..rows {
        for c in 0..cols {
            let t = ((raw[r * cols + c] - lo) / span).clamp(0.0, 1.0);
            let red = (137.0 + (243.0 - 137.0) * t) as u8;
            let green = (180.0 + (139.0 - 180.0) * t) as u8;
            let blue = (250.0 + (168.0 - 250.0) * t) as u8;
            let x = PAD + cw * c as f64;
            let y = PAD + ch * r as f64;
            out.push_str(&format!(
                "<rect x=\"{x:.1}\" y=\"{y:.1}\" width=\"{cw:.1}\" height=\"{ch:.1}\" fill=\"rgb({red},{green},{blue})\"/>"
            ));
        }
    }
    let pts = points.data();
    let xs: Vec<f64> = (0..n).map(|i| pts[i * 2]).collect();
    let ys: Vec<f64> = (0..n).map(|i| pts[i * 2 + 1]).collect();
    let (xmin, xmax) = bounds(&xs);
    let (ymin, ymax) = bounds(&ys);
    for i in 0..n {
        let cx = scale(xs[i], xmin, xmax, 0);
        let cy = scale(ys[i], ymin, ymax, 1);
        let fill = palette(labels.data()[i] as usize);
        out.push_str(&format!(
            "<circle cx=\"{cx:.1}\" cy=\"{cy:.1}\" r=\"5\" fill=\"{fill}\" stroke=\"#1e1e2e\" stroke-width=\"1.5\"/>"
        ));
    }
    write_svg_close(&mut out);
    Ok(out)
}

fn palette(idx: usize) -> &'static str {
    const COLORS: &[&str] = &[
        "#89b4fa", "#f38ba8", "#a6e3a1", "#fab387", "#cba6f7", "#94e2d5", "#f9e2af", "#eba0ac",
    ];
    COLORS[idx % COLORS.len()]
}

fn data_range(values: &[f64]) -> (f64, f64) {
    let mut lo = f64::INFINITY;
    let mut hi = f64::NEG_INFINITY;
    for &v in values {
        if v < lo {
            lo = v;
        }
        if v > hi {
            hi = v;
        }
    }
    (lo, hi)
}

